void FCrossEasy::timerEvent(QTimerEvent* t) {
 if (nIdTimer != t->timerId())
 return;
 switch(nStateTimer) {
 case 11:
 if (x5()) { y14(); nStateTimer=1; }
 break;
 case 1:
 if (x4()) { y14(); }
 else if (!x4()) { nStateTimer = 11; }
 break;
 }
}
В режимe «Потоковое управление» автомат попадает в состояние «t3».По дороге действие y17 создает класс потока. Код данного действия и код потока приведен на листинге 3.
Листинг 3. Реализация поточного режима работы
void FCrosswalk::y17() {
 QThread *pThread = thread(); // ссылка на текущий поток
 pThCrosswalk = new ThCrosswalk(this, pMainWindow);
}

ThCrosswalk::ThCrosswalk(FCrosswalk *p, QObject *parent) :
 QThread()
{
 pFCrosswalk = p;
 bIfRun = true; // установить признак запуска/завершения потока
 start(QThread::IdlePriority); // запустить поток
 nState = 11;
}
ThCrosswalk::~ThCrosswalk() {
 if (bIfRun) { bIfRun = false; quit(); wait(); }
 bIfRun = false; quit(); wait();
}
void ThCrosswalk::run()
{
 bIfStop = false; // сбросить признак останова потока
 int nSleep = 0;
 if (pMainWindow->pVarSet->bIfSynchronousOperation) {
 nSleep = pMainWindow->pVarSet->dDeltaTime;
 }
 while(bIfRun) {
 if (bIfExecuteStep) {
 bIfExecuteStep = 0;
 if (pFCrosswalk->x5()) {
 while (pFCrosswalk->x4()) {
 if (bIfExecuteStep) {
 bIfExecuteStep = 0;
 if (pFCrosswalk->nCounter == 0) {
 pFCrosswalk->y2();
 pFCrosswalk->y3();
 pFCrosswalk->y8();
 }
 if (pFCrosswalk->nCounter == 20) {
 pFCrosswalk->y1();
 pFCrosswalk->y4();
 }
 if (pFCrosswalk->nCounter == 30) {
 pFCrosswalk->y2(); pFCrosswalk->y3();
 }
 msleep(nSleep-pMainWindow->nDeltaDelta);
 pFCrosswalk->nCounter++;
 if (pFCrosswalk->nCounter == pFCrosswalk->pVarMaxCntr->GetDataSrc()) {
 pFCrosswalk->nCounter=0;
 }
 }
 }
 }
 }
 }
 bIfStop = true; // установить признак останова потока
}
Не приведенные в листингах коды методов принадлежат родительским классам. Полный код проекта, включая код автоматного ядра, размещен на GitHab и доступен по ссылке (
https://github.com/lvs628/VCPa-mini.git
). Код проекта проверен в среде Qt Creator версии 5.14.
Результаты работы теста во всех трех режимах представлены на рис. 3. Обратите внимание на время работы, где автоматная модель управления реализует наиболее точное время работы.
Рис. 3. Результаты тестирования
Заключение
Рассмотренный пример, судя по графу автомата, не отличается высокой степенью параллелизма. Это не опровергает и не подтверждает «версию» Амдала. Но, с другой стороны, каждый светофор – это параллельный процесс и в результате имеем три полностью параллельных процесса. Как все это оценить в «процентах», чтобы применить формулу Амдала, для меня загадка. Поскольку, если оценить параллелизм одного процесса светофора, то он фактически нулевой. Но, с другой стороны, мы имеем три параллельных процесса. Если их «разбросать» по ядрам, то, вероятно, будет трехкратное ускорение.
Рассмотренный в статье пример отражает очевидный факт, что параллелизм, прежде всего,
совсем не про скорость работы программы, а про решение проблемы сложности программирования
. Есть ли закон, который мог бы отразить подобное качество? У меня большие сомнения.
Рассмотренный пример отражает ситуацию, когда параллелизм есть, но скорость фактически не важна. Подобных «реальных примеров» очень и очень много, если не большинство. Тем не менее, приведенный пример можно использовать и для оценки скорости работы, уменьшая значение дискретного такта и отслеживая
пропорциональность
уменьшения времени работы.
Конечно-автоматная модель программирования позволяет дать не приближенную – в неких «попугаях» оценку, а точную оценку параллельным свойствам любого алгоритма. Это важно для определения аппаратных средств, позволяющих достичь максимальной эффективности реализации. А это и есть то, к чему стремились и мы, и Амдал, задумавший свою
качественную
оценку распараллеливания программ.
